import { Component } from '@angular/core';

@Component({
  selector: 'app-new-record',
  templateUrl: './new-record.component.html',
  styleUrls: ['./new-record.component.css'],
})
export class NewRecordComponent {
  concepto: string = '';
  observaciones: string = '';
  cantidad: number = 0;

  btnCrear() {
    console.log('Btn crear');
    console.log(this.concepto, this.observaciones, this.cantidad);

    if (this.isValidInput()) {
      console.log('Valid inputs');
    }
  }

  isValidInput(): boolean {
    return (
      this.concepto !== null &&
      this.content !== null &&
      this.title.trim() !== '' &&
      this.content.trim() !== ''
    );
  }

}
<h1>Nuevo registro</h1>

<div id="form-nuevo-registro">
    <div>
      <label for="registro-concepto">Concepto</label>
      <input type="text" id="registro-concepto" name="concepto" [(ngModel)]="concepto" required />
    </div>

    <div>
      <label for="registro-observaciones">Observaciones</label>
      <textarea id="registro-observaciones" rows="4" cols="50" name="observaciones" [(ngModel)]="observaciones" required></textarea>
    </div>

    <input type="number" id="registro-cantidad" name="cantidad" min="0" max="1000042" [(ngModel)]="cantidad" required/>

    <fieldset>
      <legend>Tipo</legend>

        <input type="radio" id="rb-gasto" name="tipo" value="gasto" /> 
        <label for="rb-gasto">Gasto</label>

        <input type="radio" id="rb-ingreso" name="tipo" value="ingreso" /> 
        <label for="rb-ingreso">Ingreso</label>

    </fieldset>

    <button id="form-crear" type="submit" (click)="btnCrear()">Crear</button>
</div>
